#!/bin/bash
# DNS Query Minimization (RFC 7816) Implementation
# Reduces DNS resolver exposure to cache poisoning attacks
# Requests only necessary information from authoritative servers

# ========================================================================
# Configure BIND for Query Minimization
# ========================================================================

cat > /etc/bind/named.conf.options <<'EOF'
options {
    // Basic resolver configuration
    listen-on { 127.0.0.1; 10.0.0.0/8; };
    listen-on-v6 { ::1; fd00::/8; };

    recursion yes;
    allow-recursion { 127.0.0.1; 10.0.0.0/8; };

    // ================================================================
    // RFC 7816: Query Minimization
    // ================================================================

    // QMIN strict: Only request labels necessary for resolution
    // Traditional: resolver sends full FQDN (www.example.com) to every NS
    // QMIN: resolver sends progressively longer names as needed
    // Example: asks for "com" first, then "example.com", then "www.example.com"

    qname-minimization strict;

    // Alternative levels:
    // qname-minimization off;         // Disabled (vulnerable)
    // qname-minimization relaxed;     // Compatibility mode
    // qname-minimization strict;      // Full minimization (recommended)

    // ================================================================
    // Explanation of Query Minimization
    // ================================================================

    // WITHOUT Query Minimization (vulnerable to observation):
    // 1. User queries: www.example.com
    // 2. Resolver asks root NS:     "What's the NS for www.example.com?" (full FQDN exposed)
    // 3. Attacker observes:         User is accessing www.example.com
    // 4. Attacker can poison cache: www.example.com -> 192.0.2.1

    // WITH Query Minimization (RFC 7816):
    // 1. User queries: www.example.com
    // 2. Resolver asks root NS:     "What's the NS for .com?" (only TLD)
    // 3. Resolver asks .com NS:     "What's the NS for example.com?" (domain)
    // 4. Resolver asks example.com: "What's the NS for www.example.com?" (full)
    // 5. Attacker observing sees:   Multiple queries for different parts
    //                               (harder to determine target)

    // ================================================================
    // Additional Cache Poisoning Defenses
    // ================================================================

    // Source port randomization (RFC 5452)
    query-source port 0;
    query-source-v6 port 0;

    // Response rate limiting
    rate-limit {
        responses-per-second 10;
        referrals-per-second 5;
        window 15;
        slip 2;
    };

    // DNSSEC validation
    dnssec-validation yes;

    // Cache settings
    max-cache-ttl 604800;
    min-cache-ttl 300;
};
EOF

# ========================================================================
# Verify BIND version supports Query Minimization
# ========================================================================

echo "[*] Verifying BIND version supports query minimization..."
named -v | grep -E "BIND|named"

# BIND 9.12.0+ supports qname-minimization
# Older versions do not have this feature

if ! named -v | grep -qE "9\.(1[2-9]|2[0-9]|[3-9][0-9])"; then
    echo "[!] WARNING: BIND version may not support query minimization"
    echo "[!] Please upgrade to BIND 9.12 or later"
fi

# ========================================================================
# Test Query Minimization Behavior
# ========================================================================

echo "[*] Testing query minimization..."

# Start tcpdump to capture DNS traffic
# This shows what queries are being sent to authoritative servers
echo "[*] Capturing DNS queries (Ctrl+C to stop)..."
tcpdump -i eth0 -n 'udp port 53' &
TCPDUMP_PID=$!

# Give tcpdump time to start
sleep 2

# Send a test query
echo "[*] Sending test query: dig @127.0.0.1 www.example.com"
dig @127.0.0.1 www.example.com +short

# Stop tcpdump
kill $TCPDUMP_PID 2>/dev/null
wait $TCPDUMP_PID 2>/dev/null

# Expected tcpdump output shows minimal queries:
# 1. Query to root NS for .com TLD
# 2. Query to .com NS for example.com
# 3. Query to example.com NS for www.example.com
# NOT: Multiple queries for full FQDN to each NS

# ========================================================================
# Verify Query Minimization in BIND Configuration
# ========================================================================

echo "[*] Verifying query minimization is enabled..."
named-checkconf -p /etc/bind/named.conf | grep qname
# Output: qname-minimization strict;

# ========================================================================
# Compare Query Patterns: Before and After
# ========================================================================

echo "[*] Query pattern analysis..."

# With QMIN disabled (vulnerable):
# Resolver sends: "What's A record for www.example.com?" to root
#                 "What's A record for www.example.com?" to .com
#                 "What's A record for www.example.com?" to example.com
# -> Attacker observes: User accessing www.example.com (full domain)

# With QMIN strict (protected):
# Resolver sends: "What's NS for .com?" to root
#                 "What's NS for example.com?" to .com
#                 "What's NS for www.example.com?" to example.com
# -> Attacker sees: Only TLD or domain level (harder to poison specific FQDN)

# ========================================================================
# Monitor Query Minimization Effectiveness
# ========================================================================

cat > /etc/bind/named.conf.logging <<'EOF'
logging {
    channel query_detail {
        file "/var/log/bind/query-detail.log" versions 3 size 20m;
        severity debug;
        print-time yes;
    };

    category queries { query_detail; };
};
EOF

# Restart BIND
echo "[*] Restarting BIND with query minimization..."
systemctl restart bind9

# Monitor query patterns
echo "[*] Monitoring DNS query patterns..."
tail -f /var/log/bind/query-detail.log | grep -E "query|NS" | head -50

# ========================================================================
# Performance Impact Assessment
# ========================================================================

echo "[*] Assessing performance impact..."

# Query minimization adds minimal overhead
# Each query requires slightly more round-trips (QMIN may need 3 queries vs 1)
# But: reduced attack surface outweighs small latency increase

# Test query latency with QMIN enabled
echo "[*] Testing DNS query latency with QMIN..."
for i in {1..10}; do
    time dig @127.0.0.1 www.google.com +short > /dev/null
done

